import { Observable, combineLatest } from "rxjs";
import { map } from "rxjs/operators";

interface Row { id: string; name: string; priceCents: number }
interface Filters { query: string; onlyInStock: boolean }
type SortKey = "name" | "priceCents";

interface TableVM {
  rows: ReadonlyArray<Row>;
  sortedBy: SortKey;
  count: number;
}

export function tableVM$(
  rows$: Observable<ReadonlyArray<Row>>,
  filters$: Observable<Filters>,
  sort$: Observable<SortKey>
): Observable<TableVM> {
  return combineLatest({ rows: rows$, f: filters$, sort: sort$ }).pipe(
    map(({ rows, f, sort }): TableVM => {
      const filtered = rows.filter((r) =>
        r.name.toLowerCase().includes(f.query.toLowerCase())
      );
      const sorted = [...filtered].sort((a, b) =>
        sort === "name"
          ? a.name.localeCompare(b.name)
          : a.priceCents - b.priceCents
      );
      return { rows: sorted, sortedBy: sort, count: sorted.length };
    })
  );
}
