import { Observable, combineLatest } from "rxjs";
import { map } from "rxjs/operators";

interface Auth { userId: string | null; roles: ReadonlyArray<string> }
interface Route { path: string; requiresAuth: boolean; requiredRole?: string }

type GuardVM =
  | { status: "allow"; path: string }
  | { status: "login"; path: string }
  | { status: "forbidden"; path: string; missingRole: string };

export function guardVM$(
  auth$: Observable<Auth>,
  route$: Observable<Route>
): Observable<GuardVM> {
  return combineLatest({ auth: auth$, route: route$ }).pipe(
    map(({ auth, route }): GuardVM => {
      if (!route.requiresAuth) return { status: "allow", path: route.path };
      if (auth.userId === null) return { status: "login", path: route.path };
      if (route.requiredRole && !auth.roles.includes(route.requiredRole)) {
        return {
          status: "forbidden",
          path: route.path,
          missingRole: route.requiredRole,
        };
      }
      return { status: "allow", path: route.path };
    })
  );
}
