import { map } from "rxjs/operators";

interface A { v: number }
interface B { w: number }
interface C { x: number }

interface Bundle {
  v: number;
  w: number;
  x: number;
}

export function bundle$(): Observable<Bundle> {
  const a$: Observable<A> = of({ v: 1 });
  const b$: Observable<B> = of({ w: 2 });
  const c$: Observable<C> = of({ x: 3 });

  return forkJoin({ a: a$, b: b$, c: c$ }).pipe(
    map(({ a, b, c }): Bundle => ({ v: a.v, w: b.w, x: c.x }))
  );
}
