import { Observable, forkJoin, of, throwError } from "rxjs";
import { map, catchError } from "rxjs/operators";

interface Visitors { today: number }
interface Revenue { cents: number }
interface Signups { count: number }
interface Errors { count: number }

type AnalyticsVM =
  | { ok: true; visitors: number; revenueCents: number; signups: number; errors: number }
  | { ok: false; message: string };

export function analytics$(): Observable<AnalyticsVM> {
  const visitors$: Observable<Visitors> = of({ today: 120 });
  const revenue$: Observable<Revenue> = of({ cents: 99_000 });
  const signups$: Observable<Signups> = of({ count: 8 });
  const errors$: Observable<Errors> = of({ count: 0 });

  return forkJoin({
    visitors: visitors$,
    revenue: revenue$,
    signups: signups$,
    errors: errors$,
  }).pipe(
    map(({ visitors, revenue, signups, errors }): AnalyticsVM => ({
      ok: true,
      visitors: visitors.today,
      revenueCents: revenue.cents,
      signups: signups.count,
      errors: errors.count,
    })),
    catchError((err: unknown) =>
      of<AnalyticsVM>({ ok: false, message: String(err) }).pipe(
        map((v) => v),
        // rethrow policy would replace this map with throwError(() => err)
      )
    ) as unknown as (source: Observable<AnalyticsVM>) => Observable<AnalyticsVM>
  ) as Observable<AnalyticsVM>;
}

// Simpler alternative without swallowing errors:
export function analyticsStrict$(): Observable<AnalyticsVM> {
  const visitors$: Observable<Visitors> = of({ today: 120 });
  const revenue$: Observable<Revenue> = of({ cents: 99_000 });
  const signups$: Observable<Signups> = of({ count: 8 });
  const errors$: Observable<Errors> = of({ count: 0 });

  return forkJoin({
    visitors: visitors$,
    revenue: revenue$,
    signups: signups$,
    errors: errors$,
  }).pipe(
    map(({ visitors, revenue, signups, errors }): AnalyticsVM => ({
      ok: true,
      visitors: visitors.today,
      revenueCents: revenue.cents,
      signups: signups.count,
      errors: errors.count,
    })),
    catchError((err: unknown) => throwError(() => err))
  );
}
