import { Observable, forkJoin, of } from "rxjs";

interface FetchResult { id: string; bytes: number }

declare function fetchOne$(id: string): Observable<FetchResult>;

export function fetchAll$(
  ids: ReadonlyArray<string>
): Observable<ReadonlyArray<FetchResult>> {
  // forkJoin over an array of observables yields Observable<T[]>.
  if (ids.length === 0) return of<ReadonlyArray<FetchResult>>([]);
  const requests: ReadonlyArray<Observable<FetchResult>> = ids.map((id) =>
    fetchOne$(id)
  );
  return forkJoin(requests);
}
