import { Observable, forkJoin, of, timer } from "rxjs";
import { map, retry } from "rxjs/operators";

interface Theme { mode: "light" | "dark" }
interface Language { tag: string }
interface Feature { name: string; enabled: boolean }

interface SettingsBundle {
  theme: Theme;
  language: Language;
  features: ReadonlyArray<Feature>;
}

const withRetry = <T>(source$: Observable<T>): Observable<T> =>
  source$.pipe(
    retry({
      count: 2,
      delay: (_err, n) => timer(2 ** n * 100),
    })
  );

export function bootstrapSettings$(): Observable<SettingsBundle> {
  const theme$: Observable<Theme> = of({ mode: "dark" });
  const language$: Observable<Language> = of({ tag: "en-US" });
  const features$: Observable<ReadonlyArray<Feature>> = of([
    { name: "beta-ui", enabled: true },
  ]);

  return forkJoin({
    theme: withRetry(theme$),
    language: withRetry(language$),
    features: withRetry(features$),
  }).pipe(
    map(({ theme, language, features }): SettingsBundle => ({
      theme,
      language,
      features,
    }))
  );
}
```

`forkJoin` waits for every input observable to *complete* before
emitting. A `BehaviorSubject` never completes on its own (you'd have to
call `.complete()`), so threading one through `forkJoin` produces an
output that never fires. Either swap it for a one-shot `of()` / HTTP
source, or take one value with `first()` / `take(1)` so it completes.

```ts
import { Observable, forkJoin, of } from "rxjs";
import { map } from "rxjs/operators";

interface User { id: string; name: string }
interface Prefs { theme: "light" | "dark" }

interface Bootstrap {
  name: string;
  theme: "light" | "dark";
}

export function bootstrap$(id: string): Observable<Bootstrap> {
  // Both sources complete after one emission — forkJoin is safe.
  const user$: Observable<User> = of({ id, name: "Ada" });
  const prefs$: Observable<Prefs> = of({ theme: "dark" });

  return forkJoin({ user: user$, prefs: prefs$ }).pipe(
    map(({ user, prefs }): Bootstrap => ({
      name: user.name,
      theme: prefs.theme,
    }))
  );
}
```

