import { Observable, forkJoin, of } from "rxjs";
import { map } from "rxjs/operators";

interface OrderSummary { id: string; totalCents: number }

declare function getSummary$(id: string): Observable<OrderSummary>;

export function summaries$(
  ids: ReadonlyArray<string>
): Observable<Readonly<Record<string, OrderSummary>>> {
  if (ids.length === 0) return of<Readonly<Record<string, OrderSummary>>>({});

  // Build a keyed object for forkJoin so we get a typed Record back.
  const sources: Record<string, Observable<OrderSummary>> = {};
  for (const id of ids) {
    sources[id] = getSummary$(id);
  }

  return forkJoin(sources).pipe(
    map((byId: Record<string, OrderSummary>) => byId)
  );
}
