```

Reach for `forkJoin` when every source is a one-shot cold observable
(an HTTP call, a promise-wrapped fetch, a `defer`) and you want a single
emission carrying the last values after all of them complete. Reach for
`combineLatest` when sources are long-lived streams and you need a live
ViewModel that updates on every change.

```ts
import { Observable, forkJoin, of } from "rxjs";
import { map } from "rxjs/operators";

interface Weather { celsius: number }
interface Forecast { cloudy: boolean }
interface Air { pm25: number }

interface WeatherReport {
  celsius: number;
  cloudy: boolean;
  pm25: number;
}

export function report$(city: string): Observable<WeatherReport> {
  const weather$: Observable<Weather> = of({ celsius: 18 });
  const forecast$: Observable<Forecast> = of({ cloudy: true });
  const air$: Observable<Air> = of({ pm25: 12 });
  void city;

  return forkJoin({
    weather: weather$,
    forecast: forecast$,
    air: air$,
  }).pipe(
    map(({ weather, forecast, air }): WeatherReport => ({
      celsius: weather.celsius,
      cloudy: forecast.cloudy,
      pm25: air.pm25,
    }))
  );
}
