```ts
import { Observable, forkJoin } from "rxjs";
import { map, take } from "rxjs/operators";

interface Theme { mode: "light" | "dark" }
interface Locale { tag: string }
interface Flags { flags: Readonly<Record<string, boolean>> }

interface SettingsSnapshot {
  theme: Theme;
  locale: Locale;
  flags: Readonly<Record<string, boolean>>;
}

export function snapshot$(
  theme$: Observable<Theme>,
  locale$: Observable<Locale>,
  flags$: Observable<Flags>
): Observable<SettingsSnapshot> {
  // take(1) completes each source after the first value so forkJoin can
  // emit. Without it, long-lived streams (BehaviorSubject, hot streams)
  // would hang the whole bundle.
  return forkJoin({
    theme: theme$.pipe(take(1)),
    locale: locale$.pipe(take(1)),
    flags: flags$.pipe(take(1)),
  }).pipe(
    map(({ theme, locale, flags }): SettingsSnapshot => ({
      theme,
      locale,
      flags: flags.flags,
    }))
  );
}
```
